   209→void CommandManager::ForeachCommand(std::function<bool (Command *)> callback) {
   210→    INSTANCE->foreachInlineCommand(callback);
   211→    INSTANCE->foreachExtendCommand(callback);
   212→}
   213→
   214→Command* CommandManager::FindCommand(const char* cmd) {
   215→    Command* result = nullptr;
   216→    auto callback = [cmd, &result](Command* command) -> bool {
   217→        if (command->get() == cmd || command->shortcut() == cmd) {
   218→            result = command;
   219→            return true;
   220→        }
   221→        return false;
   222→    };
   223→    ForeachCommand(callback);
   224→    return result;
   225→}
   226→
   227→void CommandManager::foreachInlineCommand(std::function<bool (Command *)> callback) {
   228→    for (const auto& command : inline_commands)
   229→        if (callback(command.get()))
   230→            break;
   231→}
   232→
   233→void CommandManager::foreachExtendCommand(std::function<bool (Command *)> callback) {
   234→    for (const auto& command : extend_commands)
   235→        if (callback(command.get()))
   236→            break;
   237→}
   238→
   239→void CommandManager::PushInlineCommand(Command* command) {
   240→    INSTANCE->pushInlineCommand(command);
   241→}
