    24→class Command {
    25→public:
    26→    static constexpr int ERREXIT = 10;
    27→
    28→    Command(const char* c) { command = c; }
    29→    Command(const char* c, const char* s) { command = c; shortcut_cmd = s; }
    30→
    31→    struct Options {
    32→        int optind;
    33→    };
    34→
    35→    inline std::string& get() { return command; }
    36→    inline std::string& shortcut() { return shortcut_cmd; }
    37→    virtual ~Command() {}
    38→
    39→    static constexpr int FINISH = 0;
    40→    static constexpr int CONTINUE = 1;
    41→    static constexpr int ONCHLD = 2;
    42→    virtual int prepare(int argc, char* const argv[]) { return CONTINUE; }
    43→
    44→    virtual int main(int argc, char* const argv[]) = 0;
    45→    virtual int exitMain(int argc, char* const argv[]) { return 0; }
    46→    virtual void usage() = 0;
    47→    static void Exit(int) { fflush(stdout); _exit(ERREXIT); }
    48→    int execute(int argc, char* const argv[]);
    49→private:
    50→    std::string command;
    51→    std::string shortcut_cmd;
    52→};
