    37→void UiThread::GetCommand(std::string* result) {
    38→    std::unique_lock<std::mutex> lock(cmdlock);
    39→    cond.wait(lock, [this] {
    40→        return ready;
    41→    });
    42→    result->append(cmdline);
    43→}
