    45→void UiThread::Wait() {
    46→    std::unique_lock<std::mutex> lock(execlock);
    47→    cond.wait(lock, [this] {
    48→        return !ready;
    49→    });
    50→}
    51→
    52→void UiThread::Wake() {
    53→    std::lock_guard<std::mutex> lock(execlock);
    54→    ready = false;
    55→    cond.notify_one();
    56→}
