    58→void UiThread::run() {
    59→    prepare();
    60→    shell.Init(parser());
    61→    while (1) {
    62→        {
    63→            std::lock_guard<std::mutex> lock(cmdlock);
    64→            cmdline = shell.HandleCommand();
    65→            ready = true;
    66→        }
    67→        cond.notify_one();
    68→        Wait();
    69→    }
    70→}
