    25→int Command::execute(int argc, char* const argv[]) {
    26→    int state = prepare(argc, argv);
    27→    if (state == ONCHLD) {
    28→        pid_t pid = fork();
    29→        int status;
    30→        if (pid == 0) {
    31→            struct sigaction stact;
    32→            memset(&stact, 0, sizeof(stact));
    33→            stact.sa_handler = Command::Exit;
    34→            sigaction(SIGINT, &stact, NULL);
    35→            sigaction(SIGTERM, &stact, NULL);
    36→            try {
    37→                main(argc, argv);
    38→            } catch (InvalidAddressException& e) {
    39→                LOGE("%s\n", e.what());
    40→            }
    41→            fflush(stdout);
    42→            _exit(0);
    43→        } else if (pid > 0) {
    44→            waitpid(pid, &status, 0);
    45→            if (WIFEXITED(status) && WEXITSTATUS(status) != ERREXIT) {
    46→                exitMain(argc, argv);
    47→            }
    48→        }
    49→        return 0;
    50→    } else if (state == CONTINUE) {
    51→        return main(argc, argv);
    52→    }
    53→    return FINISH;
    54→}
