    46→void MiniShell::SaveHistory(char* cmd) {
    47→    if (cmd[0] == '\0') return;
    48→
    49→    if (history_counter < HISTORY_SIZE) {
    50→        strcpy(history[history_counter], cmd);
    51→        history_counter++;
    52→        history_cursor = history_counter;
    53→    } else {
    54→        for (int i = 1; i < HISTORY_SIZE; ++i) {
    55→            strcpy(history[i - 1], history[i]);
    56→        }
    57→        strcpy(history[history_counter - 1], cmd);
    58→        history_cursor = history_counter;
    59→    }
    60→}
