    99→void MiniShell::CursorMove(int dx, int dy, bool force) {
   100→    char cursor[10];
   101→    if (dx > 0) {
   102→        if (curX + dx < totalX + 1) {
   103→            snprintf(cursor, sizeof(cursor), MOVE_RIGHT, dx);
   104→            printf("%s", cursor);
   105→            curX += dx;
   106→        }
   107→    } else {
   108→        int min = force ? 0 : minX;
   109→        if (curX - min + dx > 0) {
   110→            snprintf(cursor, sizeof(cursor), MOVE_LEFT, -dx);
